// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Place helper components here if needed

export default function Component(props: Props) {
  // State for managing component-level interactions (e.g., selected forecast day)
  const [selectedDay, setSelectedDay] = useState<number | null>(null);

  // Helper function to get weather icon/emoji based on condition
  const getWeatherIcon = (condition: string): string => {
    const normalized = condition.toLowerCase();
    if (normalized.includes('sunny') || normalized.includes('clear')) return '☀️';
    if (normalized.includes('cloudy') || normalized.includes('overcast')) return '☁️';
    if (normalized.includes('rain') || normalized.includes('rainy')) return '🌧️';
    if (normalized.includes('snow') || normalized.includes('snowy')) return '❄️';
    if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
    if (normalized.includes('wind') || normalized.includes('windy')) return '💨';
    if (normalized.includes('fog') || normalized.includes('mist')) return '🌫️';
    return '🌤️'; // default weather icon
  };

  // Helper function to get background color based on condition
  const getConditionColor = (condition: string): string => {
    const normalized = condition.toLowerCase();
    if (normalized.includes('sunny') || normalized.includes('clear')) return 'var(--ggui-color-warning-100)';
    if (normalized.includes('cloudy') || normalized.includes('overcast')) return 'var(--ggui-color-primary-100)';
    if (normalized.includes('rain') || normalized.includes('rainy')) return 'var(--ggui-color-info-100)';
    if (normalized.includes('snow') || normalized.includes('snowy')) return 'var(--ggui-color-primary-50)';
    if (normalized.includes('storm') || normalized.includes('thunder')) return 'var(--ggui-color-error-100)';
    return 'var(--ggui-color-surfaceVariant)';
  };

  // Helper function to get condition text color
  const getConditionTextColor = (condition: string): string => {
    const normalized = condition.toLowerCase();
    if (normalized.includes('sunny') || normalized.includes('clear')) return 'var(--ggui-color-warning-700)';
    if (normalized.includes('cloudy') || normalized.includes('overcast')) return 'var(--ggui-color-primary-700)';
    if (normalized.includes('rain') || normalized.includes('rainy')) return 'var(--ggui-color-info-700)';
    if (normalized.includes('snow') || normalized.includes('snowy')) return 'var(--ggui-color-primary-700)';
    if (normalized.includes('storm') || normalized.includes('thunder')) return 'var(--ggui-color-error-700)';
    return 'var(--ggui-color-onSurfaceVariant)';
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header with city name */}
        <Stack gap="var(--ggui-spacing-1)">
          <Heading level={1} color="var(--ggui-color-onSurface)">{props.city}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Current Weather</Text>
        </Stack>

        {/* Main weather card */}
        <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
          <Stack gap="var(--ggui-spacing-6)">
            {/* Current temperature and condition */}
            <Row gap="var(--ggui-spacing-6)" align="center" justify="between">
              <Stack gap="var(--ggui-spacing-4)" align="start">
                {/* Temperature display */}
                <Stack gap="var(--ggui-spacing-2)" align="start">
                  <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface)">
                    {props.temperature}°{props.unit}
                  </Text>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    {props.condition}
                  </Text>
                </Stack>
              </Stack>

              {/* Weather condition icon with background */}
              <Box
                padding="var(--ggui-spacing-6)"
                background={getConditionColor(props.condition)}
                borderRadius="var(--ggui-shape-radius-lg)"
              >
                <Text size="4xl" color={getConditionTextColor(props.condition)}>
                  {getWeatherIcon(props.condition)}
                </Text>
              </Box>
            </Row>

            {/* Divider */}
            <Divider orientation="horizontal" margin="var(--ggui-spacing-3)" color="var(--ggui-color-outlineVariant)" />

            {/* Weather metrics row */}
            <Row gap="var(--ggui-spacing-4)" justify="start">
              {/* Humidity */}
              <Stack gap="var(--ggui-spacing-1)" align="start">
                <Row gap="var(--ggui-spacing-1)" align="center">
                  <Icon name="droplets" size={16} color="var(--ggui-color-info-600)" />
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                </Row>
                <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface)">{props.humidity}%</Text>
              </Stack>

              {/* Wind Speed */}
              <Stack gap="var(--ggui-spacing-1)" align="start">
                <Row gap="var(--ggui-spacing-1)" align="center">
                  <Icon name="wind" size={16} color="var(--ggui-color-primary-600)" />
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                </Row>
                <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface)">{props.windSpeed} m/s</Text>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* 5-day forecast section */}
        {props.forecast && props.forecast.length > 0 && (
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={3} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>
            <Row gap="var(--ggui-spacing-2)" wrap={true} justify="start">
              {props.forecast.map((forecastItem, index) => (
                <Card
                  key={index}
                  as={Clickable}
                  onClick={() => setSelectedDay(selectedDay === index ? null : index)}
                  shadow={selectedDay === index ? 'md' : 'sm'}
                  padding="var(--ggui-spacing-3)"
                  radius="md"
                  style={{
                    flex: '1 1 120px',
                    minWidth: '100px',
                    cursor: 'pointer',
                    background: selectedDay === index ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                    transition: 'all 0.2s ease-in-out',
                  } as React.CSSProperties}
                  hoverStyle={{
                    background: 'var(--ggui-color-primary-100)',
                    boxShadow: 'var(--ggui-shape-shadow-md)',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                    {/* Day name */}
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" align="center">
                      {forecastItem.day || `Day ${index + 1}`}
                    </Text>

                    {/* Weather icon */}
                    <Text size="2xl">
                       {forecastItem.icon || getWeatherIcon(forecastItem.day || 'clear')}
                    </Text>

                    {/* Temperature range */}
                    <Stack gap="var(--ggui-spacing-1)" align="center">
                      {forecastItem.high !== undefined && (
                        <Row gap="var(--ggui-spacing-1)" align="center" justify="center">
                          <Text size="sm" weight="semibold" color="var(--ggui-color-onSurface)">
                            {forecastItem.high}°
                          </Text>
                        </Row>
                      )}
                      {forecastItem.low !== undefined && (
                        <Text size="xs" color="var(--ggui-color-onSurfaceVariant)">
                          Low: {forecastItem.low}°
                        </Text>
                      )}
                    </Stack>
                  </Stack>
                </Card>
              ))}
            </Row>

            {/* Expanded forecast detail for selected day */}
            {selectedDay !== null && props.forecast[selectedDay] && (
              <Card padding="var(--ggui-spacing-4)" radius="md" background="var(--ggui-color-primary-50)">
                <Stack gap="var(--ggui-spacing-2)">
                  <Heading level={4} color="var(--ggui-color-primary-700)">
                    {props.forecast[selectedDay].day || `Day ${selectedDay + 1}`} Details
                  </Heading>
                  <Text color="var(--ggui-color-primary-700)">
                    High: {props.forecast[selectedDay].high ?? 'N/A'}° | Low: {props.forecast[selectedDay].low ?? 'N/A'}°
                  </Text>
                </Stack>
              </Card>
            )}
          </Stack>
        )}
      </Stack>
    </Container>
  );
}

