import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State management for multi-step form
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [] as string[],
    comments: '',
  });

  const [errors, setErrors] = useState({
    name: '',
    email: '',
  });

  const [charCount, setCharCount] = useState(0);
  const MAX_COMMENTS = 500;

  // Validation helpers
  const isValidEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const validateStep1 = (): boolean => {
    const newErrors = { name: '', email: '' };
    let isValid = true;

    if (!formData.name.trim()) {
      newErrors.name = 'Name is required';
      isValid = false;
    }

    if (!formData.email.trim()) {
      newErrors.email = 'Email is required';
      isValid = false;
    } else if (!isValidEmail(formData.email)) {
      newErrors.email = 'Please enter a valid email address';
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  const validateStep2 = (): boolean => {
    return formData.satisfaction > 0;
  };

  const validateStep3 = (): boolean => {
    return formData.features.length > 0;
  };

  // Handler functions
  const handleNameChange = (value: string) => {
    setFormData(prev => ({ ...prev, name: value }));
    if (value.trim()) {
      setErrors(prev => ({ ...prev, name: '' }));
    }
  };

  const handleEmailChange = (value: string) => {
    setFormData(prev => ({ ...prev, email: value }));
    if (value.trim() && isValidEmail(value)) {
      setErrors(prev => ({ ...prev, email: '' }));
    }
  };

  const handleCommentsChange = (value: string) => {
    if (value.length <= MAX_COMMENTS) {
      setFormData(prev => ({ ...prev, comments: value }));
      setCharCount(value.length);
    }
  };

  const handleFeatureToggle = (feature: string) => {
    setFormData(prev => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter(f => f !== feature)
        : [...prev.features, feature],
    }));
  };

  const handleNextStep = () => {
    if (currentStep === 1 && !validateStep1()) {
      return;
    }
    if (currentStep === 2 && !validateStep2()) {
      return;
    }
    if (currentStep === 3 && !validateStep3()) {
      return;
    }
    setCurrentStep(prev => Math.min(prev + 1, 5));
  };

  const handlePrevStep = () => {
    setCurrentStep(prev => Math.max(prev - 1, 1));
  };

  const handleSubmit = () => {
    submit({
      name: formData.name,
      email: formData.email,
      satisfaction: formData.satisfaction,
      features: formData.features,
      comments: formData.comments,
    });
  };

  // Computed properties
  const isStep1Valid = formData.name.trim() && formData.email.trim() && isValidEmail(formData.email);
  const isStep2Valid = formData.satisfaction > 0;
  const isStep3Valid = formData.features.length > 0;
  const isStep4Valid = true; // Comments are optional

  const satisfactionOptions = props.satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label: label,
  }));

  const featureCheckboxes = props.featureOptions.map(feature => ({
    label: feature,
    checked: formData.features.includes(feature),
  }));

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header with title and progress */}
        <Stack gap="var(--ggui-spacing-4)">
          <Heading level={1}>Multi-Step Survey</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            Step {currentStep} of 4
          </Text>
          <Progress value={currentStep} max={4} variant="default" size="md" showLabel={false} />
        </Stack>

        {/* Step 1: Name and Email */}
        {currentStep === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Tell Us About Yourself</Heading>
              <Input
                label="Full Name"
                placeholder="John Doe"
                value={formData.name}
                onChange={handleNameChange}
                required
                error={errors.name}
              />
              <Input
                label="Email Address"
                type="email"
                placeholder="john@example.com"
                value={formData.email}
                onChange={handleEmailChange}
                required
                error={errors.email}
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>How Satisfied Are You?</Heading>
              <RadioGroup
                label="Satisfaction Rating"
                value={String(formData.satisfaction)}
                onChange={(value) => setFormData(prev => ({ ...prev, satisfaction: parseInt(value) }))}
                options={satisfactionOptions}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Which Features Interest You?</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Select at least one feature
              </Text>
              <Stack gap="var(--ggui-spacing-3)">
                {featureCheckboxes.map((feature, index) => (
                  <Checkbox
                    key={index}
                    label={feature.label}
                    checked={feature.checked}
                    onChange={() => handleFeatureToggle(feature.label)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {currentStep === 4 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Additional Comments</Heading>
              <TextArea
                label="Comments"
                placeholder="Tell us anything else you'd like us to know..."
                value={formData.comments}
                onChange={handleCommentsChange}
                maxLength={MAX_COMMENTS}
                showCount
                rows={6}
              />
            </Stack>
          </Card>
        )}

        {/* Step 5: Review */}
        {currentStep === 5 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={2}>Review Your Answers</Heading>
              <Stack gap="var(--ggui-spacing-4)">
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name</Text>
                    <Text>{formData.name}</Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email</Text>
                    <Text>{formData.email}</Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Satisfaction</Text>
                    <Text>{props.satisfactionLabels[formData.satisfaction - 1]}</Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Features Selected</Text>
                    <Text>{formData.features.join(', ') || 'None'}</Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Comments</Text>
                    <Text>{formData.comments || 'No comments provided'}</Text>
                  </Stack>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="between">
          <Button
            variant="outline"
            onClick={handlePrevStep}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          {currentStep < 5 ? (
            <Button
              variant="primary"
              onClick={handleNextStep}
              disabled={
                (currentStep === 1 && !isStep1Valid) ||
                (currentStep === 2 && !isStep2Valid) ||
                (currentStep === 3 && !isStep3Valid) ||
                (currentStep === 4 && !isStep4Valid)
              }
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleSubmit}
            >
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

