export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // State management
  const [tasks, setTasks] = useState(props.tasks || []);
  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState('low');

  // Sync tasks from props and stream updates
  useEffect(() => {
    setTasks(props.tasks || []);
  }, [props.tasks]);

  useEffect(() => {
    if (taskChanged.latest?.task) {
      const updatedTask = taskChanged.latest.task;
      setTasks(prevTasks => {
        const taskExists = prevTasks.find(t => t.id === updatedTask.id);
        if (taskChanged.latest.action === 'delete' && taskExists) {
          return prevTasks.filter(t => t.id !== updatedTask.id);
        }
        if (taskExists) {
          return prevTasks.map(t => t.id === updatedTask.id ? updatedTask : t);
        }
        return [...prevTasks, updatedTask];
      });
    }
  }, [taskChanged.latest]);

  // Handlers
  const handleMoveTask = useCallback((taskId: string, newColumn: string) => {
    setTasks(prevTasks =>
      prevTasks.map(t => t.id === taskId ? { ...t, column: newColumn } : t)
    );
    taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
  }, [taskUpdate]);

  const handleEditTask = useCallback((taskId: string, newTitle: string) => {
    setTasks(prevTasks =>
      prevTasks.map(t => t.id === taskId ? { ...t, title: newTitle } : t)
    );
    taskUpdate({ action: 'edit', taskId, data: { column: tasks.find(t => t.id === taskId)?.column || 'todo', title: newTitle } });

  const handleAddTask = useCallback((columnId: string) => {
    if (newTaskTitle.trim()) {
      const newTask = {
        id: `task-${Date.now()}`,
        title: newTaskTitle,
        priority: newTaskPriority as 'low' | 'medium' | 'high',
        column: columnId,
      };
      setTasks(prevTasks => [...prevTasks, newTask]);
      taskUpdate({ action: 'create', taskId: newTask.id, data: { column: columnId, title: newTaskTitle } });
      setNewTaskTitle('');
      setNewTaskPriority('low');
      setAddingToColumn(null);
    }
  }, [newTaskTitle, newTaskPriority, taskUpdate]);

  // Calculate task counts
  const taskCounts = useMemo(() => {
    const counts: Record<string, number> = {};
    props.columns.forEach(col => {
      counts[col.id || ''] = tasks.filter(t => t.column === col.id).length;
    });
    return counts;
  }, [tasks, props.columns]);

  const totalTasks = tasks.length;
  const completedTasks = tasks.filter(t => t.column === 'done').length;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary bar */}
        <Card padding="var(--ggui-spacing-4)" shadow="md" radius="lg">
          <Row gap="var(--ggui-spacing-4)" align="center" justify="between">
            <Stack gap="var(--ggui-spacing-2)" direction="horizontal" align="center">
              <Heading level={2}>Kanban Board</Heading>
              <Badge variant="primary" size="md">{totalTasks} Total</Badge>
              <Badge variant="success" size="md">{completedTasks} Completed</Badge>
            </Stack>
            <Progress
              value={totalTasks > 0 ? (completedTasks / totalTasks) * 100 : 0}
              max={100}
              variant="success"
              size="md"
              showLabel
            />
          </Row>
        </Card>

        {/* Kanban columns */}
        <Row gap="var(--ggui-spacing-4)" align="start" wrap>
          {props.columns.map((column) => {
            const columnTasks = tasks.filter(t => t.column === column.id);
            return (
              <Box
                key={column.id}
                style={{
                  flex: '0 1 300px',
                  minHeight: '500px',
                  background: 'var(--ggui-color-surfaceVariant)',
                  borderRadius: 'var(--ggui-shape-radius-lg)',
                  padding: 'var(--ggui-spacing-3)',
                }}
              >
                <Stack gap="var(--ggui-spacing-3)" align="stretch">
                  {/* Column header */}
                  <Row gap="var(--ggui-spacing-2)" justify="between" align="center">
                    <Heading level={3}>{column.name}</Heading>
                    <Badge variant="secondary" size="sm">
                      {taskCounts[column.id || ''] || 0}
                    </Badge>
                  </Row>

                  <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

                  {/* Task cards */}
                  <Stack gap="var(--ggui-spacing-3)" align="stretch">
                    {columnTasks.map(task => (
                      <TaskCard
                        key={task.id}
                        task={task}
                        columns={props.columns}
                        onMove={handleMoveTask}
                        onEdit={handleEditTask}
                      />
                    ))}
                  </Stack>

                  <Spacer size="flex" />

                  {/* Add Task section */}
                  {addingToColumn === column.id ? (
                    <Card padding="var(--ggui-spacing-3)" shadow="sm" radius="md" border>
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input
                          label="Task title"
                          placeholder="Enter task title..."
                          value={newTaskTitle}
                          onChange={setNewTaskTitle}
                          size="sm"
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriority}
                          onChange={setNewTaskPriority}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                          size="sm"
                        />
                        <Row gap="var(--ggui-spacing-1)" justify="end">
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => {
                              setAddingToColumn(null);
                              setNewTaskTitle('');
                              setNewTaskPriority('low');
                            }}
                          >
                            Cancel
                          </Button>
                          <Button
                            variant="primary"
                            size="sm"
                            onClick={() => handleAddTask(column.id || '')}
                          >
                            Add
                          </Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button
                      variant="outline"
                      size="sm"
                      fullWidth
                      onClick={() => setAddingToColumn(column.id || '')}
                    >
                      + Add Task
                    </Button>
                  )}
                </Stack>
              </Box>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}

