// Helper function to get element color by category
function getCategoryColor(category?: string): string {
  const colorMap: Record<string, string> = {
    'nonmetal': 'var(--ggui-color-primary-100)',
    'noble-gas': 'var(--ggui-color-info-100)',
    'alkali-metal': 'var(--ggui-color-warning-100)',
    'alkaline-earth-metal': 'var(--ggui-color-warning-50)',
    'transition-metal': 'var(--ggui-color-primary-50)',
    'lanthanide': 'var(--ggui-color-success-50)',
    'actinide': 'var(--ggui-color-error-50)',
    'metalloid': 'var(--ggui-color-primary-200)',
    'halogen': 'var(--ggui-color-success-100)',
  };
  return colorMap[category?.toLowerCase() || ''] || 'var(--ggui-color-surfaceVariant)';
}


