  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // Local state for displayed stocks and highlight tracking
  const [displayStocks, setDisplayStocks] = useState(() =>
    props.stocks ? [...props.stocks] : []
  );
  const [highlightedSymbols, setHighlightedSymbols] = useState<Set<string>>(new Set());
  const [lastUpdated, setLastUpdated] = useState(new Date());
  const highlightTimeoutRef = useRef<NodeJS.Timeout>();

  // Merge stream price updates into displayed stocks
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      const symbolToUpdate = update.symbol;

      if (symbolToUpdate) {
        setDisplayStocks((prev) => {
          const updated = prev.map((stock) =>
            stock.symbol === symbolToUpdate
              ? {
                  ...stock,
                  price: update.price ?? stock.price,
                  change: update.change ?? stock.change,
                  changePercent: update.changePercent ?? stock.changePercent,
                }
              : stock
          );
          return updated;
        });

        // Highlight the updated stock
        setHighlightedSymbols((prev) => new Set(prev).add(symbolToUpdate));
        setLastUpdated(new Date());

        // Clear highlight after animation
        if (highlightTimeoutRef.current) {
          clearTimeout(highlightTimeoutRef.current);
        }
        highlightTimeoutRef.current = setTimeout(() => {
          setHighlightedSymbols(new Set());
        }, 700);
      }
    }
  }, [priceUpdate.latest]);

  // Clean up timeout on unmount
  useEffect(() => {
    return () => {
      if (highlightTimeoutRef.current) {
        clearTimeout(highlightTimeoutRef.current);
      }
    };
  }, []);

  // Format last updated timestamp
  const formattedTime = useMemo(() => {
    return lastUpdated.toLocaleTimeString('en-US', {
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
      hour12: true,
    });
  }, [lastUpdated]);

  // Determine market status color
  const marketStatusColor =
    marketStatus.latest?.status === 'open'
      ? 'var(--ggui-color-success-600)'
      : marketStatus.latest?.status === 'closed'
      ? 'var(--ggui-color-error-600)'
      : 'var(--ggui-color-warning-600)';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
