              Market Watch
            </Heading>
            <Row gap="var(--ggui-spacing-3)" align="center">
              <div
                aria-label={`Market status: ${marketStatus.latest?.status ? marketStatus.latest.status.charAt(0).toUpperCase() + marketStatus.latest.status.slice(1) : 'Unknown'}`}
                role="status"
                style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-2)' }}>
                <div
                  style={{
                    width: '12px',
                    height: '12px',
                    borderRadius: '50%',
                    backgroundColor: marketStatusColor,
                  }}
                />
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  {marketStatus.latest?.status ? marketStatus.latest.status.charAt(0).toUpperCase() + marketStatus.latest.status.slice(1) : 'Unknown'}
                </Text>
              </div>
              <Divider orientation="vertical" margin="0" />
