                    <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface)">
                      {`${props.windSpeed}`}
                    </Text>
                  </Stack>
                </Row>
              </Row>
            </Stack>
          </Card>

          <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg" border>
            <Stack gap="var(--ggui-spacing-3)">
              <Heading level={4} color="var(--ggui-color-onSurface)">
                5-Day Forecast
              </Heading>
              {safeForecast.length === 0 ? (
                <Alert variant="info" title="No forecast data">
                  Forecast information is currently unavailable.
                </Alert>
              ) : (
                <Row gap="var(--ggui-spacing-2)" wrap>
                  {safeForecast.map((item, index) => (
                    <Card
                      key={`${item.day ?? 'day'}-${index}`}
                      as={Clickable}
                      onClick={() => setSelectedForecastIndex(index)}
                      padding="var(--ggui-spacing-3)"
