import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object
  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<number>(0);
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [touchedName, setTouchedName] = useState<boolean>(false);
  const [touchedEmail, setTouchedEmail] = useState<boolean>(false);
  const totalSteps = 5;

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const nameError = touchedName && name.trim().length === 0 ? 'Name is required.' : '';
  const emailError = touchedEmail && email.trim().length === 0 ? 'Email is required.' : touchedEmail && !emailValid ? 'Please enter a valid email address.' : '';

  const canProceed = useMemo(() => {
    if (step === 1) return name.trim().length > 0 && emailValid;
    if (step === 2) return satisfaction >= 1 && satisfaction <= 5;
    if (step === 3) return true;
    if (step === 4) return comments.length <= 500;
    return true;
  }, [step, name, emailValid, satisfaction, comments]);

  const progressValue = useMemo(() => (step / totalSteps) * 100, [step]);

  const satisfactionOptions = useMemo(
    () =>
      (props.satisfactionLabels || []).slice(0, 5).map((label, index) => ({
        value: String(index + 1),
        label: `${index + 1} - ${label}`
      })),
    [props.satisfactionLabels]
  );

  const toggleFeature = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(feature)) return prev;
        return [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const goNext = useCallback(() => {
    if (!canProceed) return;
    if (step < totalSteps) setStep(step + 1);
  }, [canProceed, step]);

  const goBack = useCallback(() => {
    if (step > 1) setStep(step - 1);
  }, [step]);

  const handleSubmit = useCallback(() => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction,
      features,
      comments: comments.trim()
    });
  }, [submit, name, email, satisfaction, features, comments]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
        <Stack gap="var(--ggui-spacing-5)">
          <Stack gap="var(--ggui-spacing-2)">
            <Row justify="between" align="center">
              <Heading level={3} color="var(--ggui-color-onSurface)">Survey Form</Heading>
              <Badge variant="primary">Step {step} of {totalSteps}</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" variant="default" />
          </Stack>

          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>About You</Heading>
              <Input
                label="Name"
                value={name}
                onChange={(value) => {
                  setName(value);
                  if (!touchedName) setTouchedName(true);
                }}
                required
                error={nameError}
                placeholder="Enter your full name"
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={(value) => {
                  setEmail(value);
                  if (!touchedEmail) setTouchedEmail(true);
                }}
                required
                error={emailError}
                placeholder="you@example.com"
              />
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Satisfaction Rating</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant)">
                Choose a rating from 1 to 5.
              </Text>
              <RadioGroup
                label="How satisfied are you?"
                value={satisfaction > 0 ? String(satisfaction) : ''}
                onChange={(value) => setSatisfaction(Number(value))}
                options={satisfactionOptions}
                error={satisfaction === 0 ? 'Please select a satisfaction rating before continuing.' : ''}
              />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Feature Interests</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant)">Select all that apply.</Text>
              <Stack gap="var(--ggui-spacing-2)">
                {(props.featureOptions || []).length === 0 && (
                  <Alert variant="info">No feature options available.</Alert>
                )}
                {(props.featureOptions || []).map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={features.includes(feature)}
                    onChange={(checked) => toggleFeature(feature, checked)}
                  />
                ))}
              </Stack>
            </Stack>
          )}

          {step === 4 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Additional Comments</Heading>
              <TextArea
                label="Comments (optional)"
                value={comments}
                onChange={setComments}
                placeholder="Share any additional feedback..."
                maxLength={500}
                showCount
                helperText="Maximum 500 characters"
              />
            </Stack>
          )}

          {step === 5 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Review Your Answers</Heading>
              <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="md">
                <Stack gap="var(--ggui-spacing-3)">
                  <Row justify="between"><Text variant="label">Name</Text><Text>{name || '—'}</Text></Row>
                  <Divider margin="var(--ggui-spacing-1)" />
                  <Row justify="between"><Text variant="label">Email</Text><Text>{email || '—'}</Text></Row>
                  <Divider margin="var(--ggui-spacing-1)" />
                  <Row justify="between"><Text variant="label">Satisfaction</Text><Text>{satisfaction > 0 ? `${satisfaction} - ${(props.satisfactionLabels || [])[satisfaction - 1] || ''}` : '—'}</Text></Row>
                  <Divider margin="var(--ggui-spacing-1)" />
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="label">Interested Features</Text>
                    <Text color="var(--ggui-color-onSurfaceVariant)">{features.length > 0 ? features.join(', ') : 'None selected'}</Text>
                  </Stack>
                  <Divider margin="var(--ggui-spacing-1)" />
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="label">Comments</Text>
                    <Text color="var(--ggui-color-onSurfaceVariant)">{comments.trim().length > 0 ? comments : 'No comments provided'}</Text>
                  </Stack>
                </Stack>
              </Card>
            </Stack>
          )}

          <Divider margin="var(--ggui-spacing-1)" />
          <Row justify="between" align="center">
            <Button variant="outline" onClick={goBack} disabled={step === 1}>
              Back
            </Button>
            {step < totalSteps ? (
              <Button
                variant="primary"
                onClick={() => {
                  if (step === 1) {
                    setTouchedName(true);
                    setTouchedEmail(true);
                  }
                  goNext();
                }}
                disabled={!canProceed}
              >
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={handleSubmit}>Submit Survey</Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>

  );
}

