import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




const PRIORITY_OPTIONS = [
  { value: 'low', label: 'Low' },
  { value: 'medium', label: 'Medium' },
  { value: 'high', label: 'High' },
];

function getPriorityVariant(priority?: 'low' | 'medium' | 'high'): 'default' | 'warning' | 'error' {
  if (priority === 'high') return 'error';
  if (priority === 'medium') return 'warning';
  return 'default';
}

function formatDueDate(value?: string): string {
  if (!value) return '';
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return value;
  return parsed.toLocaleDateString();
}

function getInitials(name?: string): string {
  if (!name) return '?';
  const parts = name.trim().split(' ').filter(Boolean);
  if (!parts.length) return '?';
  if (parts.length === 1) return parts[0].slice(0, 2).toUpperCase();
  return `${parts[0][0] ?? ''}${parts[1][0] ?? ''}`.toUpperCase();
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [tasksState, setTasksState] = useState<Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>>(props.tasks ?? []);
  const [addingColumnId, setAddingColumnId] = useState<string>('');
  const [newTaskTitle, setNewTaskTitle] = useState<string>('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');

  useEffect(() => {
    setTasksState(props.tasks ?? []);
  }, [props.tasks]);

  useEffect(() => {
    if (!taskChanged.latest || !taskChanged.latest.task) return;
    const incoming = taskChanged.latest.task;
    const incomingId = incoming.id ?? '';
    if (!incomingId) return;

    if (taskChanged.latest.action === 'delete') {
      setTasksState((prev) => prev.filter((item) => (item.id ?? '') !== incomingId));
      return;
    }

    setTasksState((prev) => {
      const idx = prev.findIndex((item) => (item.id ?? '') === incomingId);
      if (idx === -1) return [...prev, incoming];
      const next = [...prev];
      next[idx] = { ...next[idx], ...incoming };
      return next;
    });
  }, [taskChanged.latest]);

  const boardColumns = useMemo(() => {
    const base = (props.columns ?? []).filter((col) => !!col.id);
    if (!base.length) {
      return [
        { id: 'todo', name: 'To Do' },
        { id: 'in-progress', name: 'In Progress' },
        { id: 'done', name: 'Done' },
      ];
    }
    return base;
  }, [props.columns]);

  const tasksByColumn = useMemo(() => {
    const map: Record<string, Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>> = {};
    boardColumns.forEach((col) => {
      map[col.id ?? ''] = [];
    });
    (tasksState ?? []).forEach((task) => {
      const key = task.column ?? 'todo';
      if (!map[key]) map[key] = [];
      map[key].push(task);
    });
    return map;
  }, [tasksState, boardColumns]);

  const totalTasks = (tasksState ?? []).length;
  const doneColumn = boardColumns.find((col) => (col.name ?? '').toLowerCase() === 'done' || (col.id ?? '') === 'done');
  const completedCount = (tasksState ?? []).filter((task) => (task.column ?? '') === (doneColumn?.id ?? 'done')).length;

  const moveTask = useCallback((taskId: string, nextColumn: string) => {
    const existingTask = (tasksState ?? []).find((task) => (task.id ?? '') === taskId);
    const updatedTask = { ...existingTask, column: nextColumn };
    setTasksState((prev) => prev.map((task) => ((task.id ?? '') === taskId ? updatedTask : task)));
    taskUpdate({
      action: 'move',
      taskId,
      data: {
        column: updatedTask.column ?? 'todo',
        title: updatedTask.title ?? '',
        priority: updatedTask.priority ?? 'medium',
        assignee: updatedTask.assignee ?? '',
        dueDate: updatedTask.dueDate ?? '',
      } as unknown as { column: string },
    });
  }, [taskUpdate, tasksState]);

  const saveTaskTitle = useCallback((taskId: string) => {
    const trimmed = editingTitle.trim();
    if (!trimmed) {
      setEditingTaskId('');
      setEditingTitle('');
      return;
    }
    setTasksState((prev) => prev.map((task) => ((task.id ?? '') === taskId ? { ...task, title: trimmed } : task)));
    const updatedTask = { ...(tasksState.find((task) => (task.id ?? '') === taskId) ?? {}), title: trimmed };
    taskUpdate({
      action: 'edit',
      taskId,
      data: {
        column: updatedTask.column ?? 'todo',
        title: updatedTask.title ?? '',
        priority: updatedTask.priority ?? 'medium',
        assignee: updatedTask.assignee ?? '',
        dueDate: updatedTask.dueDate ?? '',
      } as unknown as { column: string },
    });
    setEditingTaskId('');
    setEditingTitle('');
  }, [editingTitle, taskUpdate, tasksState]);

  const createTask = useCallback((columnId: string) => {
    const title = newTaskTitle.trim();
    if (!title) return;
    const createdId = `task-${Date.now()}`;
    const newTask = {
      id: createdId,
      title,
      priority: newTaskPriority,
      assignee: 'Unassigned',
      column: 'todo',
      dueDate: '',
    } as { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string };

    setTasksState((prev) => [...prev, newTask]);
    taskUpdate({
      action: 'create',
      taskId: createdId,
      data: {
        column: newTask.column ?? 'todo',
        title: newTask.title ?? '',
        priority: newTask.priority ?? 'medium',
        assignee: newTask.assignee ?? '',
        dueDate: newTask.dueDate ?? '',
      } as unknown as { column: string },
    });
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddingColumnId('');
  }, [newTaskPriority, newTaskTitle, taskUpdate]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={3}>Kanban Task Board</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Track progress with live team updates ({taskChanged.all.length} updates)
              </Text>
            </Stack>
            <Row gap="var(--ggui-spacing-2)">
              <Badge variant="primary">Total: {totalTasks}</Badge>
              <Badge variant="success">Completed: {completedCount}</Badge>
            </Row>
          </Row>
        </Card>

        <Stack direction="horizontal" gap="var(--ggui-spacing-4)" wrap>
          {boardColumns.map((column) => {
            const columnId = column.id ?? '';
            const columnTasks = tasksByColumn[columnId] ?? [];
            return (
              <Card
                key={columnId || column.name}
                padding="var(--ggui-spacing-4)"
                shadow="sm"
                border
              >
                <Stack gap="var(--ggui-spacing-3)">
                  <Row justify="between" align="center">
                    <Heading level={4}>{column.name ?? 'Untitled'}</Heading>
                    <Badge variant="secondary">{columnTasks.length}</Badge>
                  </Row>

                  <Divider margin="var(--ggui-spacing-1)" />

                  <Stack gap="var(--ggui-spacing-3)">
                    {columnTasks.length === 0 ? (
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        No tasks in this column.
                      </Text>
                    ) : (
                      columnTasks.map((task) => {
                        const taskId = task.id ?? '';
                        return (
                          <Card key={taskId || task.title} padding="var(--ggui-spacing-3)" shadow="none" border>
                            <Stack gap="var(--ggui-spacing-2)">
                              <Row justify="between" align="center">
                                {editingTaskId === taskId ? (
                                  <Input
                                    label="Edit task title"
                                    value={editingTitle}
                                    onChange={setEditingTitle}
                                    placeholder="Task title"
                                  />
                                ) : (
                                  <Text
                                    as={Clickable}
                                    onDoubleClick={() => {
                                      setEditingTaskId(taskId);
                                      setEditingTitle(task.title ?? '');
                                    }}
                                    onDoubleClick={() => {
                                      setEditingTaskId(taskId);
                                      setEditingTitle(task.title ?? '');
                                    }}
                                    weight="medium"
                                  >
                                    {task.title ?? 'Untitled Task'}
                                  </Text>
                                )}
                                {editingTaskId === taskId ? (
                                  <Row gap="var(--ggui-spacing-2)">
                                    <Button size="sm" variant="primary" onClick={() => saveTaskTitle(taskId)}>
                                      Save
                                    </Button>
                                    <Button
                                      size="sm"
                                      variant="ghost"
                                      onClick={() => {
                                        setEditingTaskId('');
                                        setEditingTitle('');
                                      }}
                                    >
                                      Cancel
                                    </Button>
                                  </Row>
                                ) : (
                                  <Button size="sm" variant="ghost" onClick={() => {
                                    setEditingTaskId(taskId);
                                    setEditingTitle(task.title ?? '');
                                  }}>
                                    Edit
                                  </Button>
                                )}
                              </Row>

                              <Row gap="var(--ggui-spacing-2)" align="center" wrap>
                                <Badge variant={getPriorityVariant(task.priority)}>{task.priority ?? 'low'}</Badge>
                                <Row gap="var(--ggui-spacing-1)" align="center">
                                  <Avatar name={task.assignee ?? 'Unassigned'} size="xs" />
                                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                    {getInitials(task.assignee)}
                                  </Text>
                                </Row>
                                {task.dueDate ? (
                                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                    Due: {formatDueDate(task.dueDate)}
                                  </Text>
                                ) : null}
                              </Row>

                              <Select
                                label="Move task to"
                                value={task.column ?? ''}
                                onChange={(value) => moveTask(taskId, value)}
                                options={boardColumns
                                  .filter((col) => (col.id ?? '') !== (task.column ?? ''))
                                  .map((col) => ({
                                    value: col.id ?? '',
                                    label: col.name ?? col.id ?? '',
                                  }))}
                                placeholder="Select destination"
                              />
                            </Stack>
                          </Card>
                        );
                      })
                    )}
                  </Stack>

                  {addingColumnId === columnId ? (
                    <Card padding="var(--ggui-spacing-3)" border shadow="none">
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input
                          label="Task title"
                          value={newTaskTitle}
                          onChange={setNewTaskTitle}
                          placeholder="Enter task title"
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriority}
                          onChange={(value) => setNewTaskPriority((value as 'low' | 'medium' | 'high') || 'medium')}
                          options={PRIORITY_OPTIONS}
                        />
                        <Row gap="var(--ggui-spacing-2)">
                          <Button variant="primary" size="sm" onClick={() => createTask(columnId)}>
                            Create
                          </Button>
                          <Button variant="ghost" size="sm" onClick={() => {
                            setAddingColumnId('');
                            setNewTaskTitle('');
                            setNewTaskPriority('medium');
                          }}>
                            Cancel
                          </Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button variant="outline" size="sm" onClick={() => setAddingColumnId(columnId)}>
                      Add Task
                    </Button>
                  )}
                </Stack>
              </Card>
            );
          })}
        </Stack>
      </Stack>
    </Container>

  );
}

