import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}





// Place helper components here if needed
const getCategoryColor = (category: string): string => {
  const key = category.toLowerCase().trim().replace(/-/g, ' ');
  const map: Record<string, string> = {
    'alkali metal': 'var(--ggui-color-error-100)',
    'alkaline earth metal': 'var(--ggui-color-warning-100)',
    'transition metal': 'var(--ggui-color-primary-100)',
    'post-transition metal': 'var(--ggui-color-info-100)',
    metalloid: 'var(--ggui-color-success-100)',
    nonmetal: 'var(--ggui-color-surfaceVariant)',
    halogen: 'var(--ggui-color-warning-100)',
    'noble gas': 'var(--ggui-color-primary-200)',
    lanthanide: 'var(--ggui-color-success-100)',
    actinide: 'var(--ggui-color-error-100)',
  };
  return map[key] || 'var(--ggui-color-surfaceVariant)';
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const safeElements = useMemo(() => props.elements || [], [props.elements]);

  const filteredElements = useMemo(() => {
    const normalized = query.trim().toLowerCase();
    if (!normalized) return safeElements;
    return safeElements.filter((el) => {
      const name = (el.name || '').toLowerCase();
      const symbol = (el.symbol || '').toLowerCase();
      return name.includes(normalized) || symbol.includes(normalized);
    });
  }, [safeElements, query]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber === null) return null;
    return safeElements.find((el) => el.atomicNumber === selectedAtomicNumber) || null;
  }, [safeElements, selectedAtomicNumber]);

  const categories = useMemo(() => {
    const seen = new Set<string>();
    safeElements.forEach((el) => {
      if (el.category) seen.add(el.category);
    });
    return Array.from(seen).sort((a, b) => a.localeCompare(b));
  }, [safeElements]);

  useEffect(() => {
    if (selectedAtomicNumber === null) return;
    const exists = safeElements.some((el) => el.atomicNumber === selectedAtomicNumber);
    if (!exists) setSelectedAtomicNumber(null);
  }, [safeElements, selectedAtomicNumber]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={2}>Interactive Periodic Table</Heading>

        <Input
          label="Search elements"
          placeholder="Filter by name or symbol"
          value={query}
          onChange={setQuery}
          type="search"
          helperText="Type to filter the table"
        />

        {safeElements.length === 0 ? (
          <Alert variant="info" title="No data">
            No element data is available.
          </Alert>
        ) : filteredElements.length === 0 ? (
          <Alert variant="warning" title="No matches">
            No elements match your search.
          </Alert>
        ) : (
          <Box
            padding="var(--ggui-spacing-4)"
            background="var(--ggui-color-surfaceVariant)"
            borderRadius="var(--ggui-shape-radius-lg)"
          >
            <Box
              is="div"
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
                gap: 'var(--ggui-spacing-2)',
              }}
            >
              {filteredElements.map((el, index) => (
                <Card
                  key={`${el.atomicNumber || 'na'}-${el.symbol || 'x'}-${index}`}
                  as={Clickable}
                  onClick={() => setSelectedAtomicNumber(el.atomicNumber ?? null)}
                  hoverStyle={{
                    boxShadow: 'var(--ggui-shape-shadow-md)',
                    outline: '2px solid var(--ggui-color-primary-300)',
                    outlineOffset: '0px',
                  }}
                  padding="var(--ggui-spacing-2)"
                  shadow="sm"
                  radius="md"
                  border
                  style={{
                    gridColumn: `${el.col || 1}`,
                    gridRow: `${el.row || 1}`,
                    minHeight: '72px',
                    position: 'relative',
                    background: getCategoryColor(el.category || ''),
                    outline: selectedElement?.atomicNumber === el.atomicNumber
                      ? '2px solid var(--ggui-color-primary-600)'
                      : 'none',
                    outlineOffset: '0px',
                    transition: 'box-shadow 200ms ease, outline 200ms ease',
                  }}
                >
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant)"
                    is="span"
                    style={{ position: 'absolute', top: 'var(--ggui-spacing-1)', left: 'var(--ggui-spacing-1)' }}
                  >
                    {el.atomicNumber ?? '—'}
                  </Text>
                  <Stack justify="center" align="center" style={{ minHeight: '56px' }}>
                    <Text size="xl" weight="bold" align="center">
                      {el.symbol || '—'}
                    </Text>
                  </Stack>
                </Card>
              ))}
            </Box>
          </Box>
        )}

        <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg" border>
          <Stack gap="var(--ggui-spacing-2)">
            <Heading level={4}>Element Details</Heading>
            {selectedElement ? (
              <Stack gap="var(--ggui-spacing-1)">
                <Text><Text is="span" weight="semibold">Name: </Text>{selectedElement.name || '—'}</Text>
                <Text><Text is="span" weight="semibold">Symbol: </Text>{selectedElement.symbol || '—'}</Text>
                <Text><Text is="span" weight="semibold">Atomic Number: </Text>{selectedElement.atomicNumber ?? '—'}</Text>
                <Text><Text is="span" weight="semibold">Atomic Weight: </Text>{selectedElement.atomicWeight ?? '—'}</Text>
                <Text><Text is="span" weight="semibold">Category: </Text>{selectedElement.category || '—'}</Text>
              </Stack>
            ) : (
              <Text color="var(--ggui-color-onSurfaceVariant)">Select an element to view details.</Text>
            )}
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg" border>
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={4}>Category Legend</Heading>
            <Row wrap gap="var(--ggui-spacing-3)">
              {categories.map((category) => (
                <Row key={category} gap="var(--ggui-spacing-2)" align="center">
                  <Box
                    style={{
                      width: '16px',
                      height: '16px',
                      background: getCategoryColor(category),
                      borderRadius: 'var(--ggui-shape-radius-sm)',
                      border: '1px solid var(--ggui-color-outline)',
                    }}
                  />
                  <Text variant="bodySmall">{category}</Text>
                </Row>
              ))}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

