          const value =
            typeof record.value === 'string' || typeof record.value === 'number'
              ? String(record.value)
              : typeof record.detail === 'string'
                ? record.detail
                : 'N/A';
          return { key, value };
        }
        return { key: `Specification ${index + 1}`, value: String(item ?? 'N/A') };
      });
  }, [props.product?.specifications]);

  const parsedReviews = useMemo(() => {
    if (!Array.isArray(props.product?.reviews)) return [];
    return props.product.reviews.map((item, index) => {
      const base = item && typeof item === 'object' ? (item as Record<string, unknown>) : {};
      const author = typeof base.author === 'string' ? base.author : `Reviewer ${index + 1}`;
      const rating = typeof base.rating === 'number' ? Math.max(0, Math.min(5, Math.round(base.rating))) : 0;
      const text = typeof base.text === 'string' ? base.text : typeof base.comment === 'string' ? base.comment : 'No review text provided.';
      const date = typeof base.date === 'string' ? base.date : typeof base.createdAt === 'string' ? base.createdAt : '';
      return { author, rating, text, date };
    });
  }, [props.product?.reviews]);

  const formattedPrice = useMemo(() => {
    const amount = typeof props.product?.price === 'number' ? props.product.price : 0;
    const currencyCode = typeof props.product?.currency === 'string' && props.product.currency ? props.product.currency : 'USD';
    try {
      return new Intl.NumberFormat(undefined, { style: 'currency', currency: currencyCode }).format(amount);
    } catch (_error) {
      return `${currencyCode} ${amount.toFixed(2)}`;
    }
  }, [props.product?.price, props.product?.currency]);

  const roundedRating = useMemo(() => {
    if (typeof props.product?.rating !== 'number' || Number.isNaN(props.product.rating)) return 0;
    return Math.max(0, Math.min(5, Math.round(props.product.rating)));
  }, [props.product?.rating]);

  const isOutOfStock = safeStock <= 0;
  const isLowStock = safeStock > 0 && safeStock <= 5;

  const handleDecreaseQuantity = useCallback(() => {
    setQuantity((prev) => Math.max(1, prev - 1));
  }, []);

  const handleIncreaseQuantity = useCallback(() => {
    setQuantity((prev) => Math.min(Math.max(1, safeStock), prev + 1));
  }, [safeStock]);

  const handleAddToCart = useCallback(() => {
    if (isOutOfStock) return;
    addToCart({
      productId: String(props.product?.id ?? ''),
      quantity,
    });
  }, [addToCart, isOutOfStock, props.product?.id, quantity]);

  return (
