                  padding="var(--ggui-spacing-8)"
                  background="var(--ggui-color-primary-100)"
                  borderRadius="var(--ggui-shape-radius-md)"
                >
                  <Text align="center" weight="semibold" color="var(--ggui-color-primary-800)">
                    {props.product?.name || 'Unnamed Product'}
                  </Text>
                </Box>
              </Box>

              <Stack gap="var(--ggui-spacing-2)">
                <Heading level={2}>{props.product?.name || 'Unnamed Product'}</Heading>
                <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-primary-700)">
                  {formattedPrice}
                </Text>
                <Row gap="var(--ggui-spacing-2)" align="center" wrap>
                  <Row gap="var(--ggui-spacing-1)" align="center" aria-label={`Rated ${roundedRating} out of 5 stars`}>
                    {Array.from({ length: 5 }).map((_, index) => (
                      <Icon
                        key={`star-${index}`}
                        name={index < roundedRating ? 'star' : 'star-off'}
                        size={18}
                        color={index < roundedRating ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
                      />
                    ))}
                  </Row>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    {String(props.product?.rating ?? 0)} ({String(props.product?.reviewCount ?? parsedReviews.length)} reviews)
                  </Text>
                </Row>
                <Row gap="var(--ggui-spacing-2)" align="center">
                  <Badge variant={isLowStock ? 'warning' : 'success'}>
                    {isLowStock ? 'Low Stock' : 'In Stock'}
                  </Badge>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    {safeStock} units available
                  </Text>
                </Row>
              </Stack>
            </Row>
          </Card>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Tabs
            variant="line"
            activeKey={activeTab}
            onChange={setActiveTab}
            items={[
              {
                key: 'description',
                label: 'Description',
                content: (
                  <Stack gap="var(--ggui-spacing-3)">
                    <Text color="var(--ggui-color-onSurfaceVariant)">
                      {props.product?.description || 'No description available.'}
                    </Text>
                  </Stack>
                ),
              },
              {
                key: 'specifications',
                label: 'Specifications',
                content: (
                  <Stack gap="var(--ggui-spacing-3)">
                    {parsedSpecifications.length === 0 ? (
                      <Alert variant="info" title="No specifications">
                        Specifications are not available for this product.
                      </Alert>
                    ) : (
                      <Table
                        caption="Product specifications"
                        columns={[
                          { key: 'key', header: 'Specification' },
                          { key: 'value', header: 'Value' },
                        ]}
                        data={parsedSpecifications}
                        bordered
                      />
                    )}
                  </Stack>
                ),
              },
              {
                key: 'reviews',
                label: 'Reviews',
                content: (
                  <Stack gap="var(--ggui-spacing-3)">
                    {parsedReviews.length === 0 ? (
                      <Alert variant="info" title="No reviews yet">
                        Be the first to review this product.
                      </Alert>
                    ) : (
                      parsedReviews.map((review, index) => (
                        <Card key={`review-${index}`} padding="var(--ggui-spacing-4)" shadow="none" border>
                          <Stack gap="var(--ggui-spacing-2)">
                            <Row justify="between" align="center" wrap>
                              <Text weight="semibold">{review.author}</Text>
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                {review.date || 'Date not provided'}
                              </Text>
                            </Row>
                            <Row gap="var(--ggui-spacing-1)" align="center" aria-label={`Rated ${review.rating} out of 5 stars`}>
                              {Array.from({ length: 5 }).map((_, starIndex) => (
                                <Icon
                                  key={`review-${index}-star-${starIndex}`}
                                  name={starIndex < review.rating ? 'star' : 'star-off'}
                                  size={16}
                                  color={starIndex < review.rating ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
                                />
                              ))}
                            </Row>
                            <Text color="var(--ggui-color-onSurfaceVariant)">{review.text}</Text>
                          </Stack>
                        </Card>
                      ))
                    )}
                  </Stack>
                ),
              },
            ]}
          />
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={4}>Purchase</Heading>
            <Row gap="var(--ggui-spacing-3)" align="center" wrap>
              <Text variant="label">Quantity</Text>
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Button
                  variant="outline"
                  aria-label="Decrease quantity"
                  disabled={quantity <= 1 || isOutOfStock}
                  onPress={handleDecreaseQuantity}
                >
                  -
                </Button>
                <Box
                  padding="var(--ggui-spacing-2) var(--ggui-spacing-4)"
                  background="var(--ggui-color-surfaceVariant)"
                  borderRadius="var(--ggui-shape-radius-md)"
