type StreamTyping = { sender?: string; active?: boolean };




// Place helper components here if needed
type ChatMessageItem = { sender: string; text: string; timestamp: string };

function formatTimestamp(value: string): string {
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) {
    return value;
  }
  return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [messageInput, setMessageInput] = useState<string>('');
  const [chatMessages, setChatMessages] = useState<ChatMessageItem[]>(() =>
    (props.messages || []).map((item) => ({
      sender: item.sender || 'Unknown',
      text: item.text || '',
      timestamp: item.timestamp || new Date().toISOString(),
    }))
  );
  const [typingState, setTypingState] = useState<{ sender: string; active: boolean }>({ sender: '', active: false });
  const scrollRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setChatMessages(
      (props.messages || []).map((item) => ({
        sender: item.sender || 'Unknown',
        text: item.text || '',
        timestamp: item.timestamp || new Date().toISOString(),
      }))
    );
  }, [props.messages]);

  useEffect(() => {
    if (message.latest) {
      setChatMessages((prev) => [
        ...prev,
        {
          sender: message.latest.sender || 'Unknown',
          text: message.latest.text || '',
          timestamp: message.latest.timestamp || new Date().toISOString(),
        },
      ]);
    }
  }, [message.latest]);

  useEffect(() => {
    if (typing.latest) {
      setTypingState({
        sender: typing.latest.sender || '',
        active: Boolean(typing.latest.active),
      });
    }
  }, [typing.latest]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [chatMessages, typingState]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender: string; isCurrentUser: boolean; items: ChatMessageItem[] }> = [];
    for (let i = 0; i < chatMessages.length; i += 1) {
      const current = chatMessages[i];
      const isCurrentUser = current.sender === props.currentUser;
      const previousGroup = groups[groups.length - 1];
      if (previousGroup && previousGroup.sender === current.sender) {
        previousGroup.items.push(current);
      } else {
        groups.push({ sender: current.sender, isCurrentUser, items: [current] });
      }
    }
    return groups;
  }, [chatMessages, props.currentUser]);

  const handleSend = useCallback(() => {
    const trimmed = messageInput.trim();
    if (!trimmed) {
      return;
    }
    const timestamp = new Date().toISOString();
    sendMessage({ text: trimmed, timestamp });
    setChatMessages((prev) => [
      ...prev,
      { sender: props.currentUser, text: trimmed, timestamp },
    ]);
    setMessageInput('');
  }, [messageInput, props.currentUser, sendMessage]);

  const handleInputKeyDown = useCallback(
