              <Badge variant="primary" size="md">
                {props.participantCount} participants
              </Badge>
            </Row>
          </Row>

          {typingState.active && typingState.sender && typingState.sender !== props.currentUser && (
            <Box
              padding="var(--ggui-spacing-2)"
              background="var(--ggui-color-surfaceVariant)"
              borderRadius="var(--ggui-shape-radius-md)"
            >
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                {typingState.sender} is typing...
              </Text>
            </Box>
          )}

          <Box
            padding="var(--ggui-spacing-3)"
            background="var(--ggui-color-surface)"
            borderRadius="var(--ggui-shape-radius-md)"
          >
            <Stack
              gap="var(--ggui-spacing-3)"
              >
              <Box>
                <div
                  ref={scrollRef}
                  style={{
                    maxHeight: '55vh',
                    overflowY: 'auto',
                    paddingRight: 'var(--ggui-spacing-1)',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-3)">
                    {groupedMessages.length === 0 ? (
                      <Box
                        padding="var(--ggui-spacing-4)"
                        background="var(--ggui-color-surfaceVariant)"
                        borderRadius="var(--ggui-shape-radius-md)"
                      >
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)" align="center">
                          No messages yet.
                        </Text>
                      </Box>
                    ) : (
                      groupedMessages.map((group, groupIndex) => (
                        <Row
                          key={`${group.sender}-${groupIndex}` }
                          justify={group.isCurrentUser ? 'end' : 'start'}
                        >
                          <Box
                            padding="var(--ggui-spacing-2)"
                            background={group.isCurrentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                            borderRadius="var(--ggui-shape-radius-md)"
                          >
                            <Stack gap="var(--ggui-spacing-2)">
                              <Text
                                variant="caption"
                                weight="semibold"
                                color={group.isCurrentUser ? 'var(--ggui-color-surface)' : 'var(--ggui-color-onSurfaceVariant)'}
                              >
                                {group.sender}
                              </Text>
                              {group.items.map((item, itemIndex) => (
                                <Stack key={`${item.timestamp}-${itemIndex}`} gap="var(--ggui-spacing-1)">
                                  <Text
                                    variant="body"
                                    color={group.isCurrentUser ? 'var(--ggui-color-surface)' : 'var(--ggui-color-onSurface)'}
                                  >
                                    {item.text}
                                  </Text>
                                  <Text
                                    variant="caption"
                                    color={group.isCurrentUser ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-onSurfaceVariant)'}
                                  >
                                    {formatTimestamp(item.timestamp)}
                                  </Text>
                                </Stack>
                              ))}
                            </Stack>
                          </Box>
                        </Row>
                      ))
                    )}
                  </Stack>
                </div>
              </Box>
            </Stack>
          </Box>

          <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

          <Row gap="var(--ggui-spacing-2)" align="end">
            <Box style={{ flex: 1 } as React.CSSProperties}>
              <Input
                label="Message"
                placeholder="Type a message..."
                value={messageInput}
                onChange={setMessageInput}
                helperText="Press Enter to send"
                onKeyDown={handleInputKeyDown}
              />
            </Box>
            <Box as={Clickable} onClick={handleSend}>
