                  style={{
                    border: `1px solid ${borderColor}`,
                    borderRadius: 'var(--ggui-shape-radius-lg)',
                    padding: 'var(--ggui-spacing-4)',
                    animation: flashMap[symbol] ? 'ggui-flash 500ms ease-out' : 'none',
                    ['--ggui-flash-color' as string]: isPositive ? 'var(--ggui-color-success-100)' : 'var(--ggui-color-error-100)',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text size="3xl" weight="bold" color="var(--ggui-color-onSurface)">
                      {stock.symbol ?? '—'}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      {stock.name ?? 'Unknown Company'}
                    </Text>
                    <Text size="2xl" weight="semibold" color="var(--ggui-color-onSurface)">
                      {formatCurrency(stock.price ?? 0)}
                    </Text>
                    <Row gap="var(--ggui-spacing-2)" align="center">
                      <Text variant="bodySmall" color={trendColor}>
                        {formatSigned(stock.change ?? 0)}
                      </Text>
                      <Text
                        variant="bodySmall"
                        color={trendColor}
                        weight="medium"
                        aria-label={`${isPositive ? 'up' : 'down'} ${formatSignedPercent(stock.changePercent ?? 0)}`}
                      >
                        <Text is="span" variant="bodySmall" color={trendColor} aria-hidden="true">
                          {isPositive ? '▲' : '▼'}
                        </Text>{' '}
                        {formatSignedPercent(stock.changePercent ?? 0)}
                      </Text>
                    </Row>
                  </Stack>
                </Box>
              </Card>
            );
          })}
        </CardGrid>
      </Stack>
    </Container>

  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





// Place helper components here if needed
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

const getSafeAvatarOptions = (options: string[]): string[] => {
  if (Array.isArray(options) && options.length > 0) {
    return options.slice(0, 4);
  }
  return ['😀', '🚀', '🎨', '🧠'];
};

const getSafeRoleOptions = (options: string[]): string[] => {
  if (Array.isArray(options) && options.length > 0) {
    return options;
  }
  return ['Developer', 'Designer', 'Manager', 'Other'];
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding
  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState<string>(props.initialProfile?.email ?? '');
  const avatarChoices = useMemo(() => getSafeAvatarOptions(props.avatarOptions), [props.avatarOptions]);
  const roleChoices = useMemo(() => getSafeRoleOptions(props.roleOptions), [props.roleOptions]);
  const [avatar, setAvatar] = useState<string>(props.initialProfile?.avatar ?? avatarChoices[0] ?? '😀');
  const [role, setRole] = useState<string>(props.initialProfile?.role ?? roleChoices[0] ?? 'Developer');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(props.initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState<string>(props.initialProfile?.theme === 'dark' ? 'dark' : 'light');

  useEffect(() => {
    if (!avatar && avatarChoices[0]) {
      setAvatar(avatarChoices[0]);
    }
  }, [avatar, avatarChoices]);

  useEffect(() => {
    if (!role && roleChoices[0]) {
      setRole(roleChoices[0]);
    }
  }, [role, roleChoices]);

  const nameError = useMemo(() => {
    if (!name.trim()) return 'Name is required.';
    return '';
  }, [name]);

  const emailError = useMemo(() => {
    if (!email.trim()) return 'Email is required.';
    if (!EMAIL_REGEX.test(email.trim())) return 'Please enter a valid email address.';
    return '';
  }, [email]);

  const isStepOneValid = !nameError && !emailError && !!avatar;
  const isStepTwoValid = !!role && !!theme;
  const canGoNext = step === 1 ? isStepOneValid : isStepTwoValid;

  const goNext = useCallback(() => {
    if (step < 3 && canGoNext) {
      setStep(step + 1);
    }
  }, [step, canGoNext]);

  const goBack = useCallback(() => {
    if (step > 1) {
      setStep(step - 1);
    }
  }, [step]);

  const handleComplete = useCallback(() => {
    const payload: ActionCompletePayload = {
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    };
    complete(payload);
  }, [name, email, avatar, role, emailNotifications, theme, complete]);
  const progressValue = (step / 3) * 100;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="sm" border radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={3}>Onboarding Wizard</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
            <Row gap="var(--ggui-spacing-2)">
              <Badge variant={step >= 1 ? 'primary' : 'default'}>1. Profile</Badge>
              <Badge variant={step >= 2 ? 'primary' : 'default'}>2. Preferences</Badge>
              <Badge variant={step >= 3 ? 'primary' : 'default'}>3. Review</Badge>
            </Row>
          </Stack>
        </Card>

        <Card
          key={step}
          padding="var(--ggui-spacing-6)"
          shadow="sm"
          border
          radius="lg"
        >
          <Box
            style={{
              animation: 'ggui-fadeIn 200ms ease-out',
            }}
          >
            <Stack gap="var(--ggui-spacing-5)">
              {step === 1 && (
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={4}>Profile Setup</Heading>
                  <Input
                    label="Name"
                    required
                    value={name}
                    onChange={setName}
                    placeholder="Enter your name"
                    error={nameError || undefined}
                  />
                  <Input
                    label="Email"
                    type="email"
                    required
                    value={email}
                    onChange={setEmail}
                    placeholder="you@example.com"
                    error={emailError || undefined}
                  />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text id="avatar-group-label" variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Choose an avatar
                    </Text>
                    <Row gap="var(--ggui-spacing-3)" wrap>
                      {avatarChoices.map((emoji) => (
                        <Card
                          key={emoji}
                          as={Clickable}
                          aria-label={`Select avatar ${emoji}`}
                          role="radio" aria-checked={avatar === emoji} onClick={() => setAvatar(emoji)}
                          padding="var(--ggui-spacing-3)"
                          border
                          radius="md"
                          shadow="none"
                          style={{
                            background: avatar === emoji ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surface)',
                            borderColor: avatar === emoji ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outlineVariant)',
                            minWidth: '56px',
                            textAlign: 'center',
                            transition: 'all 200ms ease',
                          }}
                        >
                          <Text size="2xl" align="center">{emoji}</Text>
                        </Card>
                      ))}
                    </Row>
                  </Stack>
                </Stack>
              )}

              {step === 2 && (
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={4}>Preferences</Heading>
                  <Select
                    label="Role"
                    value={role}
                    onChange={setRole}
                    options={roleChoices.map((option) => ({ value: option, label: option }))}
                    placeholder="Select your role"
                    required
                  />
                  <Toggle
                    label="Email notifications"
                    checked={emailNotifications}
                    onChange={setEmailNotifications}
                  />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text id="theme-group-label" variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Theme preference
                    </Text>
                    <Row gap="var(--ggui-spacing-2)">
                      <Button
                        role="radio"
                        aria-checked={theme === 'light'}
                        aria-labelledby="theme-group-label"
                        variant={theme === 'light' ? 'primary' : 'outline'}
                        onClick={() => setTheme('light')}
                      >
                        Light
                      </Button>
                      <Button
                        role="radio"
                        aria-checked={theme === 'dark'}
                        aria-labelledby="theme-group-label"
                        variant={theme === 'dark' ? 'primary' : 'outline'}
                        onClick={() => setTheme('dark')}
                      >
                        Dark
                      </Button>
                    </Row>
                  </Stack>
                  </Stack>

              {step === 3 && (
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={4}>Review & Confirm</Heading>
                  <Card padding="var(--ggui-spacing-4)" border shadow="none" radius="md">
                    <Stack gap="var(--ggui-spacing-3)">
                      <Row justify="between"><Text variant="label">Name</Text><Text>{name || '-'}</Text></Row>
                      <Divider margin="var(--ggui-spacing-1)" />
                      <Row justify="between"><Text variant="label">Email</Text><Text>{email || '-'}</Text></Row>
                      <Divider margin="var(--ggui-spacing-1)" />
                      <Row justify="between"><Text variant="label">Avatar</Text><Text>{avatar || '-'}</Text></Row>
                      <Divider margin="var(--ggui-spacing-1)" />
                      <Row justify="between"><Text variant="label">Role</Text><Text>{role || '-'}</Text></Row>
                      <Divider margin="var(--ggui-spacing-1)" />
                      <Row justify="between"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                      <Divider margin="var(--ggui-spacing-1)" />
                      <Row justify="between"><Text variant="label">Theme</Text><Text>{theme}</Text></Row>
                    </Stack>
                  </Card>
                  <Alert variant="info" title="Almost done">
                    Review your details and complete setup.
                  </Alert>
                </Stack>
              )}

              <Divider margin="var(--ggui-spacing-2)" />
              <Row justify="between" align="center">
                <Button variant="ghost" onClick={goBack} disabled={step === 1}>
                  Back
                </Button>
                <Row gap="var(--ggui-spacing-2)">
                  {step < 3 ? (
                    <Button variant="primary" onClick={goNext} disabled={!canGoNext}>
                      Next
                    </Button>
                  ) : (
                    <>
                      <Button variant="outline" onClick={goBack}>
                        Go Back
                      </Button>
                      <Button variant="primary" onClick={handleComplete}>
                        Complete Setup
                      </Button>
                    </>
                  )}
                </Row>
              </Row>
            </Stack>
          </Box>
        </Card>
      </Stack>
    </Container>

  );
}
